int main() {
    int t;
    cin >> t;
    while (t--) {
        string s;
        cin >> s;
        int n = s.length();
        bool pass_check = true;

        for (int i = 0; i < n - 1; i += 2) {
            if (s[i] == s[i + 1]) {
                pass_check = false;
                break;
            }
        }

        if (pass_check) {
            cout << "yes" << endl;
        } else {
            cout << "no" << endl;
        }
    }
    return 0;
}

